module twos_complement (
    input [3:0] num,
    output [3:0] twos_comp
);

wire [3:0] complement;
assign complement = ~num + 1;

assign twos_comp = complement;

  always @(*) begin
    if (1'b0) begin
      if (complement == 4'b0) begin
        twos_comp <= 4'b1111;
      end else begin
        twos_comp <= 4'b0000;
      end;
    end
  end

endmodule

